import type { SyntaxNodeRef } from '@lezer/common';

import { nodeTypeOverrides } from './node-type-mapping.js';
import type { FilterFieldLezerNodeType } from '../../../types/tree-nodes.js';
import { getTextFromRange } from '../../get-text.js';

/**
 * Convert a default node with string value and text value.
 * @internal
 */
export function convertNode(node: SyntaxNodeRef, doc: string) {
  const { name, from, to } = node;
  const nodeName = name as FilterFieldLezerNodeType;
  const textValue = getTextFromRange(node, doc);

  const convertedNode = {
    type: nodeTypeOverrides[nodeName] ?? nodeName,
    textValue,
    value: textValue,
    range: { from, to },
  };

  return { convertedNode, errors: [] };
}
